ParamTypeValue = t.TypeVar("ParamTypeValue")


class ParamType:
    """Represents the type of a parameter. Validates and converts values.

    This is a minimal implementation that other concrete types can inherit
    from. Subclasses should override convert and optionally other methods.
    """

    is_composite: t.ClassVar[bool] = False
    arity: t.ClassVar[int] = 1

    #: the descriptive name of this type
    name: str = "param"

    #: environment variable splitting behavior
    envvar_list_splitter: t.ClassVar[str | None] = None

    def to_info_dict(self) -> dict[str, t.Any]:
        """Gather information useful for generating documentation.

        Subclasses may extend this to include more information.
        """
        # The class name without the "ParamType" suffix.
        param_type = type(self).__name__.partition("ParamType")[0]
        param_type = param_type.partition("ParameterType")[0]

        # Custom subclasses might not remember to set a name.
        if hasattr(self, "name"):
            name = self.name
        else:
            name = param_type

        return {"param_type": param_type, "name": name}

    def __call__(
        self,
        value: t.Any,
        param: "Parameter" | None = None,
        ctx: "Context" | None = None,
    ) -> t.Any:
        """Validate or convert a value using this parameter type.

        If the value is None, None is returned. Otherwise convert() is used.
        """
        if value is not None:
            return self.convert(value, param, ctx)

    def get_metavar(self, param: "Parameter", ctx: "Context") -> str | None:
        """Return a default metavar for help messages, if applicable."""
        return None

    def get_missing_message(self, param: "Parameter", ctx: "Context" | None) -> str | None:
        """Return additional info about a missing parameter, if any."""
        return None

    def convert(
        self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None
    ) -> t.Any:
        """Convert the given value to the proper type.

        Implementations should raise BadParameter when conversion fails.
        The base implementation accepts values unchanged.
        """
        return value


class StringParamType(ParamType):
    """Parameter type for strings."""

    name = "string"

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> str:
        """Convert the value to a string."""
        if isinstance(value, bytes):
            try:
                encoding = _get_argv_encoding()
                return value.decode(encoding)
            except Exception:
                raise BadParameter("Could not decode bytes value as string.")
        return str(value)


class BoolParamType(ParamType):
    """Parameter type for booleans."""

    name = "bool"
    truthy = {"1", "true", "yes", "on"}
    falsy = {"0", "false", "no", "off"}

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> bool:
        """Convert a value to boolean.

        Accepts booleans and common string representations.
        """
        if isinstance(value, bool):
            return value
        if isinstance(value, (int, float)):
            return bool(value)
        val = str(value).strip().lower()
        if val in self.truthy:
            return True
        if val in self.falsy:
            return False
        raise BadParameter(f"invalid boolean value: {value!r}")


class Choice(ParamType):
    """Parameter type that restricts values to a fixed set of choices."""

    is_composite = False

    def __init__(self, choices: t.Iterable[str], case_sensitive: bool = True) -> None:
        """Create a Choice type.

        :param choices: iterable of valid choice strings
        :param case_sensitive: whether comparison is case-sensitive
        """
        self.choices = list(choices)
        self.case_sensitive = bool(case_sensitive)
        self.name = "choice"

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information including the available choices."""
        info = super().to_info_dict()
        info["choices"] = list(self.choices)
        info["case_sensitive"] = self.case_sensitive
        return info

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> str:
        """Convert the value ensuring it is one of the allowed choices."""
        val = str(value)
        if not self.case_sensitive:
            lowered = [c.lower() for c in self.choices]
            if val.lower() in lowered:
                # return the canonical choice
                return self.choices[lowered.index(val.lower())]
        else:
            if val in self.choices:
                return val
        raise BadParameter(f"invalid choice: {value!r}. (choose from {', '.join(self.choices)})")


class TupleParamType(ParamType):
    """Parameter type for fixed-length tuples of other types."""

    is_composite = True

    def __init__(self, types: t.Sequence[ParamType]) -> None:
        """Create a TupleParamType with the given element types."""
        self.types = list(types)
        self.arity = len(self.types)
        self.name = "tuple"

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information about the element types."""
        return {"param_type": "tuple", "types": [t.to_info_dict() for t in self.types]}

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> tuple:
        """Convert a sequence into a tuple of converted values."""
        if isinstance(value, tuple) and all(isinstance(v, object) for v in value):
            # attempt to convert each element using corresponding type
            if len(value) != self.arity:
                raise BadParameter(f"expected {self.arity} values, got {len(value)}")
            return tuple(
                self.types[i].convert(value[i], param, ctx) for i in range(self.arity)
            )
        # If value is a string, split on commas
        if isinstance(value, str):
            parts = [p.strip() for p in value.split(",")]
            if len(parts) != self.arity:
                raise BadParameter(f"expected {self.arity} values, got {len(parts)}")
            return tuple(self.types[i].convert(parts[i], param, ctx) for i in range(self.arity))
        # Try to treat as iterable
        try:
            seq = list(value)
            if len(seq) != self.arity:
                raise BadParameter(f"expected {self.arity} values, got {len(seq)}")
            return tuple(self.types[i].convert(seq[i], param, ctx) for i in range(self.arity))
        except TypeError:
            raise BadParameter("value is not a valid sequence")


class DateTime(ParamType):
    """Parameter type that parses datetimes."""

    name = "datetime"

    def __init__(self, formats: t.Sequence[str] | None = None) -> None:
        """Create a DateTime type with optional parse formats.

        If formats is None, ISO 8601 parsing via datetime.fromisoformat is used.
        """
        self.formats = list(formats) if formats is not None else None

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information including formats if present."""
        info = super().to_info_dict()
        info["formats"] = list(self.formats) if self.formats is not None else None
        return info

    def get_metavar(self, param: "Parameter", ctx: "Context") -> str | None:
        """Return a sample metavar showing formats when available."""
        if self.formats:
            return "|".join(self.formats)
        return "DATETIME"

    def _try_to_convert_date(self, value: str) -> datetime:
        """Attempt to parse a date string using known formats."""
        if self.formats:
            for fmt in self.formats:
                try:
                    return datetime.strptime(value, fmt)
                except Exception:
                    continue
            raise BadParameter(f"datetime '{value}' does not match formats: {self.formats}")
        try:
            return datetime.fromisoformat(value)
        except Exception as e:
            raise BadParameter(f"invalid datetime value: {value!r}") from e

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> datetime:
        """Convert the given value to a datetime object."""
        if isinstance(value, datetime):
            return value
        if not isinstance(value, str):
            raise BadParameter(f"invalid datetime value: {value!r}")
        return self._try_to_convert_date(value)


class IntRange(ParamType):
    """Parameter type for integers within a range."""

    name = "int"

    def __init__(self, min: int | None = None, max: int | None = None) -> None:
        """Create an IntRange with optional bounds."""
        self.min = min
        self.max = max

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information about min and max bounds."""
        return {"param_type": "int", "min": self.min, "max": self.max}

    def _clamp(self, value: int) -> int:
        """Ensure the integer falls within the specified bounds."""
        if self.min is not None and value < self.min:
            raise BadParameter(f"Value {value} is smaller than minimum {self.min}.")
        if self.max is not None and value > self.max:
            raise BadParameter(f"Value {value} is greater than maximum {self.max}.")
        return value

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> int:
        """Convert the value to int and apply bounds checking."""
        try:
            iv = int(value)
        except Exception:
            raise BadParameter(f"{value!r} is not a valid integer")
        return self._clamp(iv)


class FloatRange(ParamType):
    """Parameter type for floats within a range."""

    name = "float"

    def __init__(self, min: float | None = None, max: float | None = None) -> None:
        """Create a FloatRange with optional bounds."""
        self.min = min
        self.max = max

    def _clamp(self, value: float) -> float:
        """Ensure the float is within bounds."""
        if self.min is not None and value < self.min:
            raise BadParameter(f"Value {value} is smaller than minimum {self.min}.")
        if self.max is not None and value > self.max:
            raise BadParameter(f"Value {value} is greater than maximum {self.max}.")
        return value

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> float:
        """Convert the value to float and apply bounds checking."""
        try:
            fv = float(value)
        except Exception:
            raise BadParameter(f"{value!r} is not a valid float")
        return self._clamp(fv)


class Path(ParamType):
    """Parameter type for filesystem paths."""

    name = "path"

    def __init__(
        self,
        exists: bool | None = None,
        file_okay: bool = True,
        dir_okay: bool = True,
        writable: bool | None = None,
        readable: bool | None = None,
        resolve_path: bool = False,
    ) -> None:
        """Create a Path parameter type.

        The flags control validation of the resolved filesystem entry.
        """
        self.exists = exists
        self.file_okay = file_okay
        self.dir_okay = dir_okay
        self.writable = writable
        self.readable = readable
        self.resolve_path = resolve_path

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information about the path constraints."""
        return {
            "param_type": "path",
            "exists": self.exists,
            "file_okay": self.file_okay,
            "dir_okay": self.dir_okay,
            "writable": self.writable,
            "readable": self.readable,
            "resolve_path": self.resolve_path,
        }

    def resolve_lazy_flag(self, ctx: "Context", value: str) -> str:
        """Resolve environment variable style flags lazily if needed.

        Default implementation simply returns the value unchanged.
        """
        return value

    def coerce_path_result(self, rv: str) -> str:
        """Allow subclasses to coerce the final path result. Default is passthrough."""
        return rv

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> str:
        """Convert the value to a filesystem path and validate it."""
        if not isinstance(value, str):
            raise BadParameter(f"{value!r} is not a valid path")
        rv = value
        if self.resolve_path:
            rv = os.path.abspath(rv)
        if self.exists is not None:
            if not os.path.exists(rv):
                raise BadParameter(f"Path '{rv}' does not exist.")
            st = os.stat(rv)
            is_dir = stat.S_ISDIR(st.st_mode)
            if is_dir and not self.dir_okay:
                raise BadParameter(f"Path '{rv}' is a directory")
            if not is_dir and not self.file_okay:
                raise BadParameter(f"Path '{rv}' is not a directory")
            if self.readable is True and not os.access(rv, os.R_OK):
                raise BadParameter(f"Path '{rv}' is not readable")
            if self.writable is True and not os.access(rv, os.W_OK):
                raise BadParameter(f"Path '{rv}' is not writable")
        return self.coerce_path_result(rv)


class File(ParamType):
    """Parameter type for file streams."""

    name = "file"

    def __init__(self, mode: str = "r", encoding: str | None = None, errors: str | None = None) -> None:
        """Create a File parameter type.

        mode, encoding, and errors are forwarded to open().
        """
        self.mode = mode
        self.encoding = encoding
        self.errors = errors

    def to_info_dict(self) -> dict[str, t.Any]:
        """Return information about the file type."""
        return {"param_type": "file", "mode": self.mode, "encoding": self.encoding}

    def _is_file_like(self, obj: t.Any) -> bool:
        """Return True if the object behaves like a file."""
        return hasattr(obj, "read") or hasattr(obj, "write")

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> t.IO:
        """Convert a filename or file-like object to a stream."""
        if value is None:
            return value
        if self._is_file_like(value):
            return value
        if isinstance(value, str):
            try:
                return open(value, self.mode, encoding=self.encoding, errors=self.errors)
            except OSError as e:
                raise BadParameter(f"Could not open file {value!r}: {e}") from e
        raise BadParameter(f"invalid value for file: {value!r}")


class UUID(ParamType):
    """Parameter type for UUIDs."""

    name = "uuid"

    def convert(self, value: t.Any, param: "Parameter" | None, ctx: "Context" | None) -> _uuid.UUID:
        """Convert a value to a UUID object."""
        if isinstance(value, _uuid.UUID):
            return value
        try:
            return _uuid.UUID(str(value))
        except Exception:
            raise BadParameter(f"{value!r} is not a valid UUID")


